<?php
namespace Tests\Feature;
use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class AccountingCloseMonthTest extends TestCase{use RefreshDatabase;
 public function test_close_month_blocks_posting_and_reopen_restores_controlled_access():void{$this->seed();$admin=User::where('email','admin@sams.local')->firstOrFail();$this->actingAs($admin)->get('/accounting');$cash=DB::table('gl_accounts')->where('code','1100')->firstOrFail();$expense=DB::table('gl_accounts')->where('code','6100')->firstOrFail();$payload=['journal_date'=>today()->toDateString(),'memo'=>'Closing seed','lines'=>[['gl_account_id'=>$expense->id,'debit'=>100,'credit'=>0],['gl_account_id'=>$cash->id,'debit'=>0,'credit'=>100]]];$this->actingAs($admin)->post('/accounting/journals',$payload);$first=DB::table('journal_entries')->firstOrFail();$this->actingAs($admin)->post('/accounting/journals/'.$first->id.'/post');$this->actingAs($admin)->get('/accounting/close-month')->assertOk()->assertSee('Still Open');$this->actingAs($admin)->post('/accounting/close-month',['year'=>today()->year,'month'=>today()->month])->assertRedirect();$lock=DB::table('transaction_period_locks')->where('module','accounting')->firstOrFail();$payload['memo']='Blocked journal';$this->actingAs($admin)->post('/accounting/journals',$payload);$second=DB::table('journal_entries')->where('memo','Blocked journal')->firstOrFail();$this->actingAs($admin)->post('/accounting/journals/'.$second->id.'/post')->assertSessionHasErrors('period');$this->assertDatabaseHas('journal_entries',['id'=>$second->id,'status'=>'draft']);$this->actingAs($admin)->delete('/accounting/close-month/'.$lock->id)->assertRedirect();$this->actingAs($admin)->post('/accounting/journals/'.$second->id.'/post')->assertRedirect();$this->assertDatabaseHas('journal_entries',['id'=>$second->id,'status'=>'posted']);$this->assertDatabaseHas('audit_logs',['event'=>'accounting_month_closed']);$this->assertDatabaseHas('audit_logs',['event'=>'accounting_month_reopened']);}
}
